+/// Render a per-comparison debug view of every scored dimension.
+///
+/// Unlike [`render_agent_eval_human`], this keeps one block per comparison
+/// instead of grouping rows into summary tables.
+pub fn render_agent_eval_human_debug(report: &AgentEvalReport) -> String {
+    let mut lines = Vec::new();
+    lines.push(format!(
+        "Valid comparisons: {}/{}",
+        report.summary.valid_pairs, report.summary.total_pairs
+    ));
+    if !report.summary.invalid_reason_counts.is_empty() {
+        let reasons: Vec<String> = report
+            .summary
+            .invalid_reason_counts
+            .iter()
+            .map(|(reason, count)| format!("{reason}={count}"))
+            .collect();
+        lines.push(format!("Invalid reasons: {}", reasons.join(", ")));
+    }
+    lines.push(String::new());
+
+    for row in &report.comparisons {
+        let treatment = row.treatment_arm.display_label();
+        lines.push(format!("Task: {} ({})", row.task_id, row.task));
+        lines.push(format!(
+            "  treatment_arm: {}",
