/// Parse changed paths from `git diff --name-only` output.
pub fn changed_files_from_git_diff(diff_output: &str) -> Vec<String> {
    diff_output
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .map(str::to_string)
        .collect()
}

