457	/// Normalize repo-relative paths so fixture gold/bridge labels match `git diff` output.
458	///
459	/// Examples:
460	/// - `codex-rs/cli/src/foo.rs` → `cli/src/foo.rs`
461	/// - `./cli/src/foo.rs` → `cli/src/foo.rs`
462	/// - `/abs/.../codex-rs/cli/src/foo.rs` → `cli/src/foo.rs`
463	pub fn normalize_agent_eval_path(path: &str) -> String {
464	    let path = path.trim().replace('\\', "/");
465	    if path.is_empty() {
466	        return String::new();
467	    }
468	    let path = path.trim_start_matches("./");
469	    if let Some(idx) = path.find("/codex-rs/") {
470	        return path[idx + "/codex-rs/".len()..].to_string();
471	    }
472	    let mut rest = path;
473	    while let Some(stripped) = rest.strip_prefix("codex-rs/") {
474	        rest = stripped;
475	    }
476	    rest.to_string()
477	}
