515	pub fn score_run(record: &AgentRunRecord, task: &AgentEvalTask) -> AgentRunScore {
516	    let gold: BTreeSet<String> = task.relevant_files.iter().cloned().collect();
517	    let bridge: BTreeSet<String> = task.bridge_files.iter().cloned().collect();
518	    let target: BTreeSet<String> = gold.union(&bridge).cloned().collect();
519	    // Source of truth for "what did the model edit?" — prefer
520	    // `intent_changed_files` (from authoritative `file_change` events),
521	    // fall back to `changed_files` (raw git diff) for pre-instrumented
522	    // records. The rate_limit-v2 rerun showed `git diff` over-counts
523	    // by 4-7x when the model runs `just fmt`, so anchoring on intent
524	    // is required for `extra_files` and `orientation_files_touched`
525	    // to mean what their names say.
526	    let source = if record.intent_changed_files.is_empty() {
527	        &record.changed_files
528	    } else {
529	        &record.intent_changed_files
530	    };
531	    let changed: BTreeSet<String> = filter_scoring_changed_files(source)
532	        .into_iter()
533	        .map(|path| normalize_agent_eval_path(&path))
534	        .filter(|path| !path.is_empty())
535	        .collect();
536	    let correct_file_touched = gold.iter().any(|path| changed.contains(path));
537	    let target_files_hit = target.intersection(&changed).count();
538	    let target_files_total = target.len();
539	    let unnecessary_files_changed: Vec<String> = changed.difference(&gold).cloned().collect();
540	    let bridge_files_touched: Vec<String> = bridge.intersection(&changed).cloned().collect();
541	
542	    // Orientation set: every file the directive labeled "orientation
543	    // only" for this arm, plus the fixture's bridge_files (which the
544	    // new directive rendering treats as orientation by default). Then
545	    // subtract the gold so an edit to a gold path doesn't double-count
546	    // as an over-broaden. Vanilla arms have no `ri_surfaced_*` data,
547	    // so their orientation_set collapses to (bridge − gold).
548	    let ri_orientation: BTreeSet<String> = record
549	        .ri_surfaced_orientation
550	        .iter()
551	        .map(|p| normalize_agent_eval_path(p))
552	        .filter(|p| !p.is_empty())
553	        .collect();
554	    let orientation_set: BTreeSet<String> = bridge
555	        .union(&ri_orientation)
556	        .filter(|p| !gold.contains(*p))
557	        .cloned()
558	        .collect();
559	    let edit_target_files_hit = gold.intersection(&changed).count();
560	    let edit_target_files_total = gold.len();
561	    let orientation_files_touched = orientation_set.intersection(&changed).count();
562	    let orientation_files_total = orientation_set.len();
563	
564	    AgentRunScore {
565	        correct_file_touched,
566	        target_files_hit,
567	        target_files_total,
568	        tests_passed: record.tests_passed && record.run_valid,
569	        turn_count: record.turn_count,
570	        unnecessary_files_changed,
