593	/// Decide the comparison verdict using the priority order
594	/// `file_targeting > fewer_extra_files > fewer_turns > fewer_tokens`. Cheaper
595	/// is never preferred over correctness — token comparison runs last.
596	pub fn classify_result(
597	    vanilla: &AgentRunScore,
598	    treatment: &AgentRunScore,
599	    valid_for_comparison: bool,
600	    excluded_reason: Option<&str>,
601	) -> AgentEvalResult {
602	    if !valid_for_comparison {
603	        let reason = excluded_reason.unwrap_or("invalid").to_string();
604	        return AgentEvalResult::Excluded { reason };
605	    }
606	
607	    if treatment.target_files_hit > vanilla.target_files_hit {
608	        return AgentEvalResult::RiBetter {
609	            reason: ResultReason::FileTargeting,
610	        };
611	    }
612	    if treatment.target_files_hit < vanilla.target_files_hit {
613	        return AgentEvalResult::RiWorse {
614	            reason: ResultReason::FileTargeting,
615	        };
616	    }
617	
618	    let v_extra = vanilla.unnecessary_files_changed.len();
619	    let t_extra = treatment.unnecessary_files_changed.len();
620	    if t_extra < v_extra {

