 917	/// Coarse classification of a single shell command into one of five phases.
 918	/// Returned as a static slug for both Rust scoring and the bash mirror.
 919	///
 920	/// Limitations: stateless (can't tell "cat before edit" from "cat after"),
 921	/// and a single command can serve multiple purposes (`grep -n` is discover;
 922	/// `grep -A 3` is verify). The heuristic favors the most common case for
 923	/// each shell tool as observed in q8 / qwen3-coder traces. Two refinements
 924	/// from the 2026-05-25 rehearsal:
 925	///
 926	/// 1. `cd <dir> && <real_cmd>` chains: agents often prefix every shell with
 927	///    `cd $WORKTREE && ...`. We strip every leading `cd ... &&` segment and
 928	///    classify by the actual command that follows.
 929	/// 2. `grep -A5` (no space between flag and number) counts as verify, same
 930	///    as `grep -A 5`.
 931	pub fn classify_shell_phase(command: &str) -> &'static str {
 932	    let normalized = strip_leading_cd_chains(command);
 933	    let first = first_executable_token(&normalized);
 934	    match first {
 935	        "find" | "ls" | "tree" | "locate" | "fd" => "discover",
 936	        "cat" | "head" | "tail" | "less" | "more" => "read",
 937	        "grep" | "rg" | "ack" => {
 938	            // Context flags indicate post-edit verify, not discovery.
 939	            // Match BOTH spaced (`-A 3`) and joined (`-A3`) variants, plus
 940	            // long forms. Use lowercase for case-insensitivity.
 941	            let lc = normalized.to_ascii_lowercase();
 942	            let has_context = lc.contains(" -a ")
 943	                || lc.contains(" -b ")
 944	                || lc.contains(" -c ")
 945	                || lc.contains(" -a=")
 946	                || lc.contains(" -b=")
 947	                || lc.contains(" -c=")
 948	                || lc.contains(" --after-context")
 949	                || lc.contains(" --before-context")
 950	                || lc.contains(" --context")
 951	                // -A5 / -B5 / -C5 (joined form). Single-digit suffix matched
 952	                // by checking " -A<d>" / " -B<d>" / " -C<d>" where d is a
 953	                // digit. Cheap byte scan; no regex dependency.
 954	                || has_joined_context_flag(&lc);
 955	            if has_context { "verify" } else { "discover" }
 956	        }
 957	        "sed" => {
 958	            if command.contains("-i") {
 959	                "edit"
 960	            } else {
 961	                "other"
 962	            }
 963	        }
 964	        "perl" => {
